#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=2e3+5;
int a[MAXN][MAXN],n1,m1,n2,m2,k,colour,sl=0,sr=0,l=0,r=0;
signed main(void)
{
    // freopen("in.txt","r",stdin);
    // freopen("out.txt","w",stdout);
	n1=read(),m1=read(),n2=read(),m2=read(),k=read();
	FOR(i,1,n1)
	{
		FOR(j,1,m1)
		{
			a[i][j]=read();
			if(a[i][j]==999999)
			{
				a[i][j]=0;
				colour=(!((i&1)^(j&1)));
			}
			sr+=a[i][j]*((!((i&1)^(j&1))));
			sl+=a[i][j]*((((i&1)^(j&1))));
			r+=((!((i&1)^(j&1))));
			l+=((((i&1)^(j&1))));
		}
	}
	FOR(i,n1+1,n1+n2)
	{
		FOR(j,1,m2)
		{
			a[i][j]=read();
			if(a[i][j]==999999)
			{
				a[i][j]=0;
				colour=(!((i&1)^(j&1)));
			}
			sr+=a[i][j]*((!((i&1)^(j&1))));
			sl+=a[i][j]*((((i&1)^(j&1))));
			r+=((!((i&1)^(j&1))));
			l+=((((i&1)^(j&1))));
		}
	}
	if(r!=l)sr-=k;
	if(colour==0)
	{
		write(sr-sl);
	}
	else
	{
		write(sl-sr);
	}
    return false;
}
